log.warn(`[config-debug] config.retrieval keys: ${JSON.stringify(Object.keys(config2.retrieval || {}))}`);
log.warn(`[config-debug] config.retrieval.rerankApiKey: ${config2.retrieval?.rerankApiKey ? "SET(" + String(config2.retrieval.rerankApiKey).substring(0, 8) + ")" : "EMPTY"}`);
var retriever = createRetriever(store, embedder, {
  ...DEFAULT_RETRIEVAL_CONFIG,
  ...config2.retrieval
});
var scopeManager = createScopeManager(config2.scopes);
var semanticGate = new SemanticGate(embedder);
store.setSemanticGate(semanticGate);
